import React, { useRef } from "react";
import "../styles/Team.css";
import { FaLinkedin, FaGithub } from "react-icons/fa";

const teamMembers = [
  { name: "Rupankar Garai", role: "4 Years of Freelancing Experience as a Full-Stack Developer Empowering Projects with Code & Creativity | Tech + Academic Partner", imgSrc: "profile/Rupankar.jpg", linkedin: "#", github: "#" },
   { name: "Sayan Maity", role: "Advanced Data Analytics & ML Intern", imgSrc: "/images/sayan.jpg", linkedin: "#", github: "#" },
  { name: "Tridib Kamal", role: "Cyber Security Analyst", imgSrc: "/images/anupam.jpg", linkedin: "#", github: "#" },
  { name: "Anisha Roy", role: "UI/UX Designer", imgSrc: "/images/anisha.jpg", linkedin: "#" },
  { name: "Dev Sharma", role: "DevOps Engineer", imgSrc: "/images/dev.jpg", linkedin: "#" },
  { name: "Sneha Gupta", role: "Full Stack Developer", imgSrc: "/images/sneha.jpg", linkedin: "#" },
  { name: "Ravi Singh", role: "AI/ML Intern", imgSrc: "/images/ravi.jpg", linkedin: "#", github: "#" },
  { name: "Megha Kapoor", role: "Marketing Head", imgSrc: "/images/megha.jpg", linkedin: "#" },
  { name: "Ishaan Verma", role: "Product Manager", imgSrc: "/images/ishaan.jpg", linkedin: "#" },
];

export default function Team() {
  const carouselRef = useRef(null);

  const scroll = (direction) => {
    const cardWidth = 300 + 32; // Card width + gap (2rem = 32px)
    if (carouselRef.current) {
      carouselRef.current.scrollBy({
        left: direction === "next" ? cardWidth : -cardWidth,
        behavior: "smooth",
      });
    }
  };

  return (
    <section className="team-section">
      <h2>Our Team</h2>
      <p>
        Meet our talented team of professionals dedicated to delivering exceptional solutions.
      </p>

      <div className="team-carousel" ref={carouselRef}>
        {teamMembers.map((member, idx) => (
          <div className="team-card" key={idx}>
            <div className="image-container">
              <img loading="lazy" src={member.imgSrc} alt={member.name} />
            </div>
            <h3>{member.name}</h3>
            <p className="role">{member.role}</p>
            <div className="social-icons">
              {member.linkedin && (
                <a href={member.linkedin} target="_blank" rel="noopener noreferrer" aria-label={`${member.name}'s LinkedIn`}>
                  <FaLinkedin />
                </a>
              )}
              {member.github && (
                <a href={member.github} target="_blank" rel="noopener noreferrer" aria-label={`${member.name}'s GitHub`}>
                  <FaGithub />
                </a>
              )}
            </div>
          </div>
        ))}
      </div>

      <div className="carousel-nav">
        <button onClick={() => scroll("prev")}>&larr; Previous</button>
        <button onClick={() => scroll("next")}>Next &rarr;</button>
      </div>
    </section>
  );
}
